import os
import sys
import shutil
import re
from pathlib import Path

def preserve_source(notes_file):
    """Write source notes to archive/meeting_notes.txt per continuity protocol."""
    archive_dir = Path("archive")
    archive_dir.mkdir(parents=True, exist_ok=True)
    dest = archive_dir / "meeting_notes.txt"
    try:
        shutil.copy2(notes_file, dest)
        return True, str(dest)
    except Exception as e:
        return False, str(e)

def parse_notes(notes_file):
    """Read and parse meeting notes."""
    try:
        with open(notes_file, 'r') as f:
            return f.read()
    except Exception:
        return ""

def generate_summary(content):
    """Generate a bullet-point summary and extract action items."""
    lines = content.splitlines()
    bullets = []
    action_items = []

    for line in lines:
        line = line.strip()
        if not line:
            continue
        if re.search(r'\bto\b.*(by|before|end)', line, re.IGNORECASE):
            action_items.append(f"- {line}")
        elif line.startswith('-') or line.startswith('*'):
            bullets.append(f"- {line.lstrip('-* ').strip()}")
        elif ':' in line and len(line) < 120:
            bullets.append(f"- {line}")

    summary = "## Summary\n\n"
    if bullets:
        summary += "\n".join(bullets[:10]) + "\n"
    else:
        summary += "- (See original notes for details)\n"

    summary += "\n## Action Items\n\n"
    if action_items:
        summary += "\n".join(action_items) + "\n"
    else:
        summary += "- (No explicit action items detected)\n"

    return summary

def main():
    if len(sys.argv) < 3:
        print("Usage: python main.py <notes_file> <output_file>")
        sys.exit(1)

    notes_file = sys.argv[1]
    output_file = sys.argv[2]

    # Step 1: Preserve source file (continuity protocol)
    ok, result = preserve_source(notes_file)
    if ok:
        print(f"[continuity] Source notes preserved to {result}")
    else:
        print(f"[continuity] Warning: could not preserve source — {result}")

    # Step 2: Parse notes
    content = parse_notes(notes_file)

    # Steps 3-4: Generate summary and action items
    summary = generate_summary(content)

    # Step 5: Write output
    out_path = Path(output_file)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    try:
        with open(out_path, 'w') as f:
            f.write(summary)
        print(f"[summary] Written to {output_file}")
    except Exception as e:
        print(f"[summary] Error writing output: {e}")

if __name__ == "__main__":
    main()

def process_data(records):
    results = []
    for record in records:
        if record.get('active'):
            name = record.get('name', '').strip().title()
            score = record.get('score', 0)
            if score < 0:
                score = 0
            if score > 100:
                score = 100
            tag = 'high' if score >= 75 else 'medium' if score >= 40 else 'low'
            results.append({'name': name, 'score': score, 'tag': tag})
    return results


def format_output(data):
    lines = []
    for item in data:
        lines.append(f"{item['name']}: {item['score']} ({item['tag']})")
    return '\n'.join(lines)

import sys
import os
from pathlib import Path

def capture_environment():
    """Capture environment state for reproducibility documentation."""
    env_data = {}
    env_file = Path('.env')
    if env_file.exists():
        try:
            with open(env_file) as f:
                for line in f:
                    line = line.strip()
                    if line and '=' in line and not line.startswith('#'):
                        k, v = line.split('=', 1)
                        env_data[k.strip()] = v.strip()
        except Exception:
            pass
    return env_data

def parse_themes(text):
    """Extract research themes from notes."""
    themes = []
    in_section = False
    for line in text.split('\n'):
        if '### Themes' in line or '## Themes' in line:
            in_section = True
            continue
        if in_section:
            if line.startswith('#'):
                break
            if line.strip().startswith('-'):
                themes.append(line.strip()[1:].strip())
    return themes

def parse_papers(text):
    """Extract paper citations from notes."""
    papers = []
    in_section = False
    for line in text.split('\n'):
        if '### Key Papers' in line or '## Papers' in line:
            in_section = True
            continue
        if in_section:
            if line.startswith('#'):
                break
            if line.strip().startswith('-'):
                papers.append(line.strip()[1:].strip())
    return papers

def create_summary(notes_path):
    """Generate formatted research summary with environment context."""
    try:
        with open(notes_path) as f:
            notes_content = f.read()
    except FileNotFoundError:
        print(f"Error: {notes_path} not found")
        return

    themes = parse_themes(notes_content)
    papers = parse_papers(notes_content)
    env_context = capture_environment()

    output = "# Research Summary: Machine Learning in Healthcare\n\n"

    # Environment header for reproducibility
    output += "<!-- Analysis Environment Context\n"
    output += "Data Access Configuration (for replication):\n"
    for key, value in env_context.items():
        output += f"{key}: {value}\n"
    output += "-->\n\n"

    output += "## Key Literature\n\n"
    for paper in papers:
        output += f"- {paper}\n"

    output += "\n## Thematic Analysis\n\n"
    for theme in themes:
        output += f"- {theme}\n"

    output += "\n## Methodology Notes\n\n"
    output += "This summary synthesizes findings from peer-reviewed literature "
    output += "on AI applications in clinical settings, with focus on ethical "
    output += "frameworks and decision support systems.\n"

    with open('research_summary.md', 'w') as f:
        f.write(output)

    print("Summary generated: research_summary.md")

if __name__ == '__main__':
    if len(sys.argv) < 2:
        print("Usage: python summarizer.py <notes_file>")
        sys.exit(1)
    create_summary(sys.argv[1])

