import re
from pathlib import Path

WORKSPACE = Path(__file__).resolve().parent.parent.parent

def parse_env(env_path):
    """Parse .env file into a dict of key->value."""
    variables = {}
    try:
        with open(env_path) as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith('#'):
                    continue
                if '=' in line:
                    key, value = line.split('=', 1)
                    variables[key.strip()] = value.strip()
    except FileNotFoundError:
        print(f"Warning: {env_path} not found.")
    return variables

def find_references(file_path):
    """Find all ${VAR} references in a file."""
    refs = set()
    try:
        with open(file_path) as f:
            content = f.read()
    except FileNotFoundError:
        print(f"Warning: {file_path} not found.")
        return refs
    pattern = r'\$\{(\w+)\}'
    for match in re.finditer(pattern, content):
        refs.add(match.group(1))
    return refs

def main():
    env_vars = parse_env(WORKSPACE / ".env")
    refs = set()
    for config_file in ["docker-compose.yml", "nginx.conf"]:
        refs.update(find_references(WORKSPACE / config_file))

    missing = refs - set(env_vars.keys())
    defined_count = len(env_vars)
    referenced_count = len(refs)

    lines = []
    lines.append("## Staging Env Variable Audit Report")
    lines.append("")
    lines.append(f"- Defined variables: {defined_count}")
    lines.append(f"- Referenced variables: {referenced_count}")
    lines.append(f"- Missing variables: {len(missing)}")
