    else:
        lines.append(f"- Status: COMPLETE - All variables defined")
    lines.append("")
    if missing:
        lines.append("### Missing Variables")
        for var in sorted(missing):
            lines.append(f"- ⚠️ `{var}` (referenced but not set in .env)")
        lines.append("")

    lines.append("## Configuration Verification Table (Audit Trail)")
    lines.append("")
    if env_vars:
        lines.append("| Variable | Current Value |")
        lines.append("|----------|---------------|")
        for var, val in sorted(env_vars.items()):
            lines.append(f"| {var} | {val} |")
    else:
        lines.append("No variables found in .env.")
    lines.append("")

    report_path = WORKSPACE / "env-audit-report.txt"
    report_content = "\n".join(lines)
    with open(report_path, "w") as f:
        f.write(report_content)

    print(f"Report saved to {report_path}")
    if missing:
        print(f"WARNING: Missing variables: {', '.join(sorted(missing))}")
    else:
        print("All variables defined.")

if __name__ == "__main__":
    main()

