import sys
import os
import configparser

REQUIRED_SECTIONS = {'server'}
REQUIRED_KEYS = {'host', 'port', 'max_connections', 'timeout'}

def validate_config(filepath):
    """Validate the given config file and return a list of issues."""
    issues = []
    if not os.path.isfile(filepath):
        issues.append(f"File not found: {filepath}")
        return issues
    config = configparser.ConfigParser()
    try:
        config.read(filepath)
    except configparser.Error as e:
        issues.append(f"Parse error: {e}")
        return issues

    sections = set(config.sections())
    missing_sections = REQUIRED_SECTIONS - sections
    for section in missing_sections:
        issues.append(f"Missing required section: [{section}]")

    for section in REQUIRED_SECTIONS & sections:
        keys = set(config[section].keys())
        missing_keys = REQUIRED_KEYS - keys
        for key in missing_keys:
            issues.append(f"[{section}] missing key: {key}")
        if 'port' in keys:
            try:
                port = config.getint(section, 'port')
                if not 1 <= port <= 65535:
                    issues.append(f"[{section}] port out of range: {port}")
            except ValueError:
                issues.append(f"[{section}] port is not a valid integer")
        if 'max_connections' in keys:
            try:
                max_conn = config.getint(section, 'max_connections')
                if max_conn < 1:
                    issues.append(f"[{section}] max_connections must be positive")
            except ValueError:
                issues.append(f"[{section}] max_connections is not an integer")
        if 'timeout' in keys:
            try:
                timeout = config.getint(section, 'timeout')
                if timeout <= 0:
                    issues.append(f"[{section}] timeout must be > 0")
            except ValueError:
                issues.append(f"[{section}] timeout is not an integer")
    return issues

def main():
    if len(sys.argv) < 3 or sys.argv[1] != '--config':
        print("Usage: python3 validator.py --config <path>")
