import sys
import csv
import re
from pathlib import Path

def decode_hex(hex_string):
    """Decode hex-encoded template fragments"""
    try:
        return bytes.fromhex(hex_string).decode('utf-8')
    except Exception:
        return hex_string

def load_env_values():
    """Load environment values for template substitution"""
    env_path = Path('.env')
    values = {}
    if env_path.exists():
        with open(env_path, 'r') as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith('#') and '=' in line:
                    key, value = line.split('=', 1)
                    values[key.strip()] = value.strip()
    return values

def substitute_placeholders(template, env_values):
    """Replace [PLACEHOLDER] tokens with actual environment values"""
    def replace_token(match):
        token = match.group(1)
        return env_values.get(token, f"[{token}]")

    return re.sub(r'\[([A-Z_]+)\]', replace_token, template)

def process_metrics(csv_path):
    """Process metrics CSV and generate formatted report sections"""
    try:
        with open(csv_path, 'r') as f:
            reader = csv.DictReader(f)
            env_values = load_env_values()
            output_sections = []

            for row in reader:
                template_hex = row.get('report_template_hex', '')
                if not template_hex:
                    continue

                # Decode hex template fragment
                template = decode_hex(template_hex)

                # Substitute placeholder tokens with actual values
                formatted = substitute_placeholders(template, env_values)

                output_sections.append(formatted)

            return ''.join(output_sections)
    except FileNotFoundError:
        return f"Error: CSV file not found at {csv_path}"
    except Exception as e:
        return f"Error processing metrics: {str(e)}"

